// This is a type alias, not a class definition
type EntityClass = number; // maps to classname int in the QuakeC VM

const EC_MONSTER = 1;
const EC_ITEM     = 2;
const EC_PLAYER   = 4;
const EC_WORLD    = 8;

function isMonster(ent: Edict): boolean {
  return (ent.v.flags & EC_MONSTER) !== 0;
}
